import{_ as e,c as s,o as t,a1 as i}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"v1.0.0-v1.0.1: 初始版本与修复 | opencode-mystatus","description":"了解 opencode-mystatus v1.0.0 初始版本的新功能，包括多平台额度查询、可视化进度条、多语言支持，以及 v1.0.1 修复的斜杠命令问题。","frontmatter":{"title":"v1.0.0-v1.0.1: 初始版本与修复 | opencode-mystatus","sidebarTitle":"v1.0.0-v1.0.1","subtitle":"v1.0.0-v1.0.1: 初始版本与修复","description":"了解 opencode-mystatus v1.0.0 初始版本的新功能，包括多平台额度查询、可视化进度条、多语言支持，以及 v1.0.1 修复的斜杠命令问题。","tags":["Version","Changelog","v1.0.0","v1.0.1"],"order":999},"headers":[],"relativePath":"vbgate/opencode-mystatus/changelog/v100-v101/index.md","filePath":"vbgate/opencode-mystatus/changelog/v100-v101/index.md"}'),n={name:"vbgate/opencode-mystatus/changelog/v100-v101/index.md"};function o(l,a,d,r,p,h){return t(),s("div",null,[...a[0]||(a[0]=[i(`<h1 id="v1-0-0-v1-0-1-initial-release-and-slash-command-fixes" tabindex="-1">v1.0.0 - v1.0.1: Initial Release and Slash Command Fixes <a class="header-anchor" href="#v1-0-0-v1-0-1-initial-release-and-slash-command-fixes" aria-label="Permalink to &quot;v1.0.0 - v1.0.1: Initial Release and Slash Command Fixes&quot;">​</a></h1><h2 id="version-overview" tabindex="-1">Version Overview <a class="header-anchor" href="#version-overview" aria-label="Permalink to &quot;Version Overview&quot;">​</a></h2><p><strong>v1.0.0</strong> (2026-01-11) is the initial release of opencode-mystatus, introducing core features for multi-platform quota queries.</p><p><strong>v1.0.1</strong> (2026-01-11) was released immediately after, addressing a critical issue with slash command support.</p><hr><h2 id="v1-0-1-slash-command-fixes" tabindex="-1">v1.0.1 - Slash Command Fixes <a class="header-anchor" href="#v1-0-1-slash-command-fixes" aria-label="Permalink to &quot;v1.0.1 - Slash Command Fixes&quot;">​</a></h2><h3 id="fixed-issues" tabindex="-1">Fixed Issues <a class="header-anchor" href="#fixed-issues" aria-label="Permalink to &quot;Fixed Issues&quot;">​</a></h3><p><strong>Included <code>command/</code> Directory in npm Package</strong></p><ul><li><strong>Issue</strong>: After the v1.0.0 release, the slash command <code>/mystatus</code> was not working properly</li><li><strong>Root Cause</strong>: The <code>command/</code> directory was missing from the npm package, preventing OpenCode from recognizing the slash command</li><li><strong>Solution</strong>: Updated the <code>files</code> field in <code>package.json</code> to ensure the <code>command/</code> directory is included in the published package</li><li><strong>Impact</strong>: Only affects users who installed via npm; manual installations are not affected</li></ul><h3 id="upgrade-recommendations" tabindex="-1">Upgrade Recommendations <a class="header-anchor" href="#upgrade-recommendations" aria-label="Permalink to &quot;Upgrade Recommendations&quot;">​</a></h3><p>If you have already installed v1.0.0, we recommend upgrading to v1.0.1 immediately to get full slash command support:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## Upgrade to the latest version</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @vbgate/opencode-mystatus</span></span></code></pre></div><hr><h2 id="v1-0-0-initial-release" tabindex="-1">v1.0.0 - Initial Release <a class="header-anchor" href="#v1-0-0-initial-release" aria-label="Permalink to &quot;v1.0.0 - Initial Release&quot;">​</a></h2><h3 id="new-features" tabindex="-1">New Features <a class="header-anchor" href="#new-features" aria-label="Permalink to &quot;New Features&quot;">​</a></h3><p><strong>1. Multi-Platform Quota Queries</strong></p><p>One-click quota usage queries for the following platforms:</p><table tabindex="0"><thead><tr><th>Platform</th><th>Supported Subscription Types</th><th>Quota Types</th></tr></thead><tbody><tr><td>OpenAI</td><td>Plus/Team/Pro</td><td>3-hour quota, 24-hour quota</td></tr><tr><td>Zhipu AI</td><td>Coding Plan</td><td>5-hour Token limit, MCP monthly quota</td></tr><tr><td>Google Cloud</td><td>Antigravity</td><td>G3 Pro, G3 Image, G3 Flash, Claude</td></tr></tbody></table><p><strong>2. Visual Progress Bars</strong></p><p>Intuitively display quota usage:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>OpenAI (user@example.com)</span></span>
<span class="line"><span>━━━━━━━━━━━━━━━━━━━━ 75%</span></span>
<span class="line"><span>Used 750 / 1000 requests</span></span></code></pre></div><p><strong>3. Multi-Language Support</strong></p><ul><li>Chinese (Simplified)</li><li>English</li></ul><p>Language auto-detection, no manual switching required.</p><p><strong>4. API Key Masking</strong></p><p>All sensitive information (API Key, OAuth Token) is automatically masked for security:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Zhipu AI (zhipuai-coding-plan)</span></span>
<span class="line"><span>API Key: sk-a1b2****xyz</span></span></code></pre></div><hr><h2 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;Usage&quot;">​</a></h2><h3 id="slash-command-recommended" tabindex="-1">Slash Command (Recommended) <a class="header-anchor" href="#slash-command-recommended" aria-label="Permalink to &quot;Slash Command (Recommended)&quot;">​</a></h3><p>Type in OpenCode:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/mystatus</span></span></code></pre></div><h3 id="natural-language" tabindex="-1">Natural Language <a class="header-anchor" href="#natural-language" aria-label="Permalink to &quot;Natural Language&quot;">​</a></h3><p>You can also ask using natural language:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Check my AI platform quotas</span></span></code></pre></div><hr><h2 id="upgrade-guide" tabindex="-1">Upgrade Guide <a class="header-anchor" href="#upgrade-guide" aria-label="Permalink to &quot;Upgrade Guide&quot;">​</a></h2><h3 id="upgrade-from-v1-0-0-to-v1-0-1" tabindex="-1">Upgrade from v1.0.0 to v1.0.1 <a class="header-anchor" href="#upgrade-from-v1-0-0-to-v1-0-1" aria-label="Permalink to &quot;Upgrade from v1.0.0 to v1.0.1&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @vbgate/opencode-mystatus</span></span></code></pre></div><p>After upgrading, restart OpenCode to use the slash command <code>/mystatus</code>.</p><h3 id="first-time-installation" tabindex="-1">First-Time Installation <a class="header-anchor" href="#first-time-installation" aria-label="Permalink to &quot;First-Time Installation&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @vbgate/opencode-mystatus</span></span></code></pre></div><p>After installation, type <code>/mystatus</code> in OpenCode to query all platform quotas.</p><hr><h2 id="known-limitations" tabindex="-1">Known Limitations <a class="header-anchor" href="#known-limitations" aria-label="Permalink to &quot;Known Limitations&quot;">​</a></h2><ul><li>v1.0.0 does not support GitHub Copilot (added in v1.2.0)</li><li>v1.0.0 does not support Z.ai (added in v1.1.0)</li></ul><p>To use these features, please upgrade to the latest version.</p><hr><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>Check out the <a href="./../v120-v124/">v1.2.0 - v1.2.4 Changelog</a> to learn about new features like GitHub Copilot support.</p>`,50)])])}const g=e(n,[["render",o]]);export{c as __pageData,g as default};
